   156→  // Update explainability trace (convert to ExplainabilityTrace.MultiLabelResult format)
   157→  const multiLabelResults: Array<{
   158→    selectedCategories: string[];
   159→    rejectedCategories: Array<{
   160→      category: string;
   161→      score: number;
   162→      rejectionReason: string;
   163→    }>;
   164→    coPresenceRulesApplied: string[];
   165→    maxLabelsLimit: number;
   166→    minSecondaryConfidence: number;
   167→    reason: string;
   168→  }> = [
