   179→              : 'Exceeded max labels limit or failed combination rules',
   180→        })),
   181→      coPresenceRulesApplied: [], // Populated based on allowed combinations
   182→      maxLabelsLimit: config.maxLabels,
   183→      minSecondaryConfidence: config.minSecondaryConfidence,
   184→      reason:
   185→        selectedLabels.length > 0
   186→          ? `Selected ${selectedLabels.length} labels with primary: ${selectedLabels.find((l) => l.isPrimary)?.category || selectedLabels[0].category}`
   187→          : 'No labels met minimum confidence threshold',
   188→    },
   189→  ];
