   191→  result.explainabilityTrace.multiLabelSelection = multiLabelResults;
   192→  result.explainabilityTrace.stageTimings['multiLabelSelection'] = duration;
   193→  result.explainabilityTrace.configurationRefs['multiLabelSelection'] = 'settings.multiLabelSelection';
   194→}
